Below is a simple HTML file that uses JavaScript and CSS to create animated bar charts comparing bubble sort with quicksort and mergesort. The file includes step counters and complexity explanations.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Sorting Algorithm Comparison</title>
    <style>
        body {
            font-family: Arial, sans-serif;
        }
        .chart-container {
            display: flex;
            justify-content: space-between;
            margin-bottom: 20px;
        }
        .chart {
            width: 45%;
            border: 1px solid #ddd;
            padding: 10px;
        }
        .bar {
            width: 10px;
            background-color: #007bff;
            display: inline-block;
            margin: 2px;
        }
    </style>
</head>
<body>
    <h1>Sorting Algorithm Comparison</h1>
    <div class="chart-container">
        <div class="chart" id="bubble-sort-chart"></div>
        <div class="chart" id="quicksort-chart"></div>
    </div>
    <div class="chart-container">
        <div class="chart" id="mergesort-chart"></div>
    </div>
    <button id="sort-button">Sort</button>
    <p id="complexity-explanation"></p>
    <p id="step-counter"></p>

    <script>
        // Data to sort
        let data = [];
        for (let i = 0; i < 20; i++) {
            data.push(Math.floor(Math.random() * 100));
        }

        // Bubble sort
        function bubbleSort(data, chartId, stepCounter) {
            let steps = 0;
            let n = data.length;
            for (let i = 0; i < n; i++) {
                for (let j = 0; j < n - i - 1; j++) {
                    steps++;
                    if (data[j] > data[j + 1]) {
                        [data[j], data[j + 1]] = [data[j + 1], data[j]];
                        renderChart(data, chartId, steps);
                        stepCounter.textContent = `Steps: ${steps}`;
                        awaitSleep(10);
                    }
                }
            }
            return steps;
        }

        // Quicksort
        function quicksort(data, low, high, chartId, stepCounter) {
            let steps = 0;
            if (low < high) {
                let pivotIndex = partition(data, low, high, chartId, stepCounter);
                steps += high - low;
                stepCounter.textContent = `Steps: ${steps}`;
                awaitSleep(10);
                quicksort(data, low, pivotIndex - 1, chartId, stepCounter);
                quicksort(data, pivotIndex + 1, high, chartId, stepCounter);
            }
            return steps;
        }

        function partition(data, low, high, chartId, stepCounter) {
            let pivot = data[high];
            let i = low - 1;
            for (let j = low; j < high; j++) {
                if (data[j] < pivot) {
                    i++;
                    [data[i], data[j]] = [data[j], data[i]];
                    renderChart(data, chartId, stepCounter.textContent);
                    awaitSleep(10);
                }
            }
            [data[i + 1], data[high]] = [data[high], data[i + 1]];
            renderChart(data, chartId, stepCounter.textContent);
            awaitSleep(10);
            return i + 1;
        }

        // Mergesort
        function mergesort(data, low, high, chartId, stepCounter) {
            let steps = 0;
            if (low < high) {
                let mid = Math.floor((low + high) / 2);
                steps += 1;
                stepCounter.textContent = `Steps: ${steps}`;
                awaitSleep(10);
                mergesort(data, low, mid, chartId, stepCounter);
                mergesort(data, mid + 1, high, chartId, stepCounter);
                merge(data, low, mid, high, chartId, stepCounter);
            }
            return steps;
        }

        function merge(data, low, mid, high, chartId, stepCounter) {
            let left = data.slice(low, mid + 1);
            let right = data.slice(mid + 1, high + 1);
            let i = 0, j = 0, k = low;
            while (i < left.length && j < right.length) {
                if (left[i] <= right[j]) {
                    data[k] = left[i];
                    i++;
                } else {
                    data[k] = right[j];
                    j++;
                }
                k++;
                renderChart(data, chartId, stepCounter.textContent);
                awaitSleep(10);
            }
            while (i < left.length) {
                data[k] = left[i];
                i++;
                k++;
                renderChart(data, chartId, stepCounter.textContent);
                awaitSleep(10);
            }
            while (j < right.length) {
                data[k] = right[j];
                j++;
                k++;
                renderChart(data, chartId, stepCounter.textContent);
                awaitSleep(10);
            }
        }

        // Render chart
        function renderChart(data, chartId, steps) {
            let chart = document.getElementById(chartId);
            chart.innerHTML = '';
            data.forEach((value) => {
                let bar = document.createElement('div');
                bar.className = 'bar';
                bar.style.height = `${value}px`;
                chart.appendChild(bar);
            });
        }

        // Sleep function
        function awaitSleep(ms) {
            return new Promise(resolve => setTimeout(resolve, ms));
        }

        // Main function
        async function main() {
            let bubbleSortData = [...data];
            let quicksortData = [...data];
            let mergesortData = [...data];

            let stepCounterBubble = document.getElementById('step-counter');
            let stepCounterQuicksort = document.getElementById('step-counter');
            let stepCounterMergesort = document.getElementById('step-counter');

            document.getElementById('complexity-explanation').textContent = 'Bubble sort: O(n^2), Quicksort: O(n log n) on average, Mergesort: O(n log n)';

            renderChart(bubbleSortData, 'bubble-sort-chart');
            renderChart(quicksortData, 'quicksort-chart');
            renderChart(mergesortData, 'mergesort-chart');

            let bubbleSortButton = document.getElementById('sort-button');
            bubbleSortButton.addEventListener('click', async () => {
                stepCounterBubble.textContent = 'Steps: 0';
                let bubbleSortSteps = await bubbleSort(bubbleSortData, 'bubble-sort-chart', stepCounterBubble);
                console.log(`Bubble sort steps: ${bubbleSortSteps}`);

                let quicksortSteps = await quicksort(quicksortData, 0, quicksortData.length - 1, 'quicksort-chart', stepCounterQuicksort);
                console.log(`Quicksort steps: ${quicksortSteps}`);

                let mergesortSteps = await mergesort(mergesortData, 0, mergesortData.length - 1, 'mergesort-chart', stepCounterMergesort);
                console.log(`Mergesort steps: ${mergesortSteps}`);
            });
        }

        main();
    </script>
</body>
</html>
```
The HTML file above creates a simple web page with three bar charts representing the data to be sorted. When you click the "Sort" button, the page will animate the sorting process for bubble sort, quicksort, and mergesort, displaying the step count for each algorithm.

**Time Complexity Comparison:**

*   Bubble sort: O(n^2)
*   Quicksort: O(n log n) on average, O(n^2) in the worst case
*   Mergesort: O(n log n)

**Space Complexity Comparison:**

*   Bubble sort: O(1)
*   Quicksort: O(log n) for the recursive call stack
*   Mergesort: O(n) for the auxiliary array used during merging

Keep in mind that while bubble sort may seem simple and intuitive, its O(n^2) time complexity makes it impractical for large datasets. Quicksort and mergesort, on the other hand, have an average time complexity of O(n log n), making them more suitable for most use cases. However, the choice of sorting algorithm ultimately depends on the specific requirements and constraints of your project.

Below is a simple HTML file that includes animated bar charts comparing bubble sort with quicksort and mergesort. This example uses JavaScript and HTML5 canvas to create the animated bar charts.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Sorting Algorithm Comparison</title>
    <style>
        canvas {
            border: 1px solid black;
        }
    </style>
</head>
<body>
    <h1>Sorting Algorithm Comparison</h1>
    <canvas id="canvas" width="800" height="400"></canvas>
    <button id="start-button">Start</button>
    <p id="step-counter"></p>
    <p id="complexity-explanation"></p>

    <script>
        // Get the canvas and context
        const canvas = document.getElementById('canvas');
        const ctx = canvas.getContext('2d');

        // Get the start button and step counter elements
        const startButton = document.getElementById('start-button');
        const stepCounterElement = document.getElementById('step-counter');
        const complexityExplanationElement = document.getElementById('complexity-explanation');

        // Define the sorting algorithms
        function bubbleSort(arr) {
            let steps = 0;
            for (let i = 0; i < arr.length; i++) {
                for (let j = 0; j < arr.length - i - 1; j++) {
                    steps++;
                    if (arr[j] > arr[j + 1]) {
                        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
                    }
                    draw(arr, arr.slice().sort((a, b) => a - b), steps);
                    await(10);
                }
            }
            return steps;
        }

        async function quickSort(arr, low, high, steps) {
            if (low < high) {
                let pivotIndex = await partition(arr, low, high, steps);
                steps = quickSort(arr, low, pivotIndex - 1, steps);
                steps = quickSort(arr, pivotIndex + 1, high, steps);
            }
            return steps;
        }

        async function partition(arr, low, high, steps) {
            let pivot = arr[high];
            let i = low - 1;
            for (let j = low; j < high; j++) {
                steps++;
                if (arr[j] < pivot) {
                    i++;
                    [arr[i], arr[j]] = [arr[j], arr[i]];
                }
                draw(arr, arr.slice().sort((a, b) => a - b), steps);
                await(10);
            }
            [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];
            draw(arr, arr.slice().sort((a, b) => a - b), steps);
            await(10);
            return i + 1;
        }

        function mergeSort(arr, low, high, steps) {
            if (low < high) {
                let mid = Math.floor((low + high) / 2);
                steps = mergeSort(arr, low, mid, steps);
                steps = mergeSort(arr, mid + 1, high, steps);
                steps = merge(arr, low, mid, high, steps);
            }
            return steps;
        }

        function merge(arr, low, mid, high, steps) {
            let left = arr.slice(low, mid + 1);
            let right = arr.slice(mid + 1, high + 1);
            let i = 0, j = 0, k = low;
            while (i < left.length && j < right.length) {
                steps++;
                if (left[i] <= right[j]) {
                    arr[k] = left[i];
                    i++;
                } else {
                    arr[k] = right[j];
                    j++;
                }
                k++;
                draw(arr, arr.slice().sort((a, b) => a - b), steps);
                await(10);
            }
            while (i < left.length) {
                arr[k] = left[i];
                i++;
                k++;
                steps++;
                draw(arr, arr.slice().sort((a, b) => a - b), steps);
                await(10);
            }
            while (j < right.length) {
                arr[k] = right[j];
                j++;
                k++;
                steps++;
                draw(arr, arr.slice().sort((a, b) => a - b), steps);
                await(10);
            }
            return steps;
        }

        // Function to draw the bar charts
        function draw(arr1, arr2, arr3, steps) {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            ctx.fillStyle = 'blue';
            for (let i = 0; i < arr1.length; i++) {
                ctx.fillRect(i * 2, canvas.height - arr1[i] * 2, 2, arr1[i] * 2);
            }
            ctx.fillStyle = 'red';
            for (let i = 0; i < arr2.length; i++) {
                ctx.fillRect(i * 2 + 200, canvas.height - arr2[i] * 2, 2, arr2[i] * 2);
            }
            ctx.fillStyle = 'green';
            for (let i = 0; i < arr3.length; i++) {
                ctx.fillRect(i * 2 + 400, canvas.height - arr3[i] * 2, 2, arr3[i] * 2);
            }
            stepCounterElement.textContent = `Steps: ${steps}`;
        }

        // Function to await
        function await(ms) {
            return new Promise(resolve => setTimeout(resolve, ms));
        }

        // Start the sorting process
        startButton.addEventListener('click', async () => {
            let arr = Array(20).fill(0).map(() => Math.floor(Math.random() * 100));
            let bubbleArr = arr.slice();
            let quickArr = arr.slice();
            let mergeArr = arr.slice();
            let sortedArr = arr.slice().sort((a, b) => a - b);

            complexityExplanationElement.textContent = `
                <h2>Time Complexity:</h2>
                <ul>
                    <li>Bubble Sort: O(n^2)</li>
                    <li>Quicksort: O(n log n) on average, O(n^2) in worst case</li>
                    <li>Merge Sort: O(n log n)</li>
                </ul>
            `;

            let bubbleSteps = await bubbleSort(bubbleArr);
            console.log(`Bubble sort steps: ${bubbleSteps}`);

            let quickSteps = 0;
            await quickSort(quickArr, 0, quickArr.length - 1, quickSteps);
            console.log(`Quicksort steps: ${quickSteps}`);

            let mergeSteps = mergeSort(mergeArr, 0, mergeArr.length - 1, 0);
            console.log(`Merge sort steps: ${mergeSteps}`);

            while (true) {
                draw(bubbleArr, quickArr, mergeArr, 0);
                await(1000);
            }
        });
    </script>
</body>
</html>
```

This code creates a canvas with three bar charts representing the three sorting algorithms. The `bubbleSort`, `quickSort`, and `mergeSort` functions sort the arrays and update the canvas after each swap. The step counter and complexity explanations are also displayed.

Note that the `await` function is used to create a delay between each step of the sorting process, making it easier to visualize. The `draw` function clears the canvas and redraws the bar charts with the current state of the arrays.

When you open this HTML file in a browser and click the "Start" button, it will start the sorting process and display the animated bar charts. The step counter and complexity explanations will also be updated.

