*   Bubble Sort: O(n^2)
*   Quicksort: O(n log n) on average, O(n^2) in worst case
*   Merge Sort: O(n log n)

**Space Complexity:**

*   Bubble Sort: O(1)
*   Quicksort: O(log n) in average case, O(n) in worst case
*   Merge Sort: O(n)

Here's a simple HTML file that uses JavaScript and HTML5 Canvas to visualize bubble sort, quicksort, and mergesort. This file will create a simple animated bar chart comparing the three algorithms.

```html
<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Sorting Algorithm Comparison</title>
    <style>
        body {
            font-family: Arial, sans-serif;
        }
        canvas {
            border: 1px solid black;
        }
    </style>
</head>
<body>
    <h1>Sorting Algorithm Comparison</h1>
    <p>Bubble Sort: O(n^2) - Not suitable for large datasets</p>
    <p>Quicksort: O(n log n) on average, O(n^2) in worst case - Fast and efficient</p>
    <p>Mergesort: O(n log n) - Stable and efficient</p>
    <canvas id="canvas" width="800" height="400"></canvas>
    <button id="start-button">Start</button>

    <script>
        // Get the canvas element
        const canvas = document.getElementById('canvas');
        const ctx = canvas.getContext('2d');

        // Set the canvas dimensions
        const canvasWidth = canvas.width;
        const canvasHeight = canvas.height;

        // Define the algorithms
        const algorithms = {
            bubbleSort: bubbleSort,
            quicksort: quicksort,
            mergesort: mergesort
        };

        // Define the data
        let data = [];
        const dataSize = 20;

        // Initialize the data
        function initData() {
            data = [];
            for (let i = 0; i < dataSize; i++) {
                data.push(Math.floor(Math.random() * 100));
            }
        }

        // Draw the data
        function drawData(data1, data2, data3) {
            ctx.clearRect(0, 0, canvasWidth, canvasHeight);
            const barWidth = canvasWidth / (3 * dataSize);
            for (let i = 0; i < dataSize; i++) {
                ctx.fillStyle = 'blue';
                ctx.fillRect(i * barWidth * 3, canvasHeight - data1[i], barWidth, data1[i]);
                ctx.fillStyle = 'red';
                ctx.fillRect(i * barWidth * 3 + barWidth, canvasHeight - data2[i], barWidth, data2[i]);
                ctx.fillStyle = 'green';
                ctx.fillRect(i * barWidth * 3 + barWidth * 2, canvasHeight - data3[i], barWidth, data3[i]);
            }
        }

        // Bubble sort
        async function bubbleSort(data, stepCounter) {
            for (let i = 0; i < data.length; i++) {
                for (let j = 0; j < data.length - i - 1; j++) {
                    if (data[j] > data[j + 1]) {
                        [data[j], data[j + 1]] = [data[j + 1], data[j]];
                        stepCounter.textContent = `Bubble Sort Steps: ${i * (data.length - i - 1) + j}`;
                        await new Promise(resolve => requestAnimationFrame(resolve));
                        drawData(data, data2, data3);
                    }
                }
            }
        }

        // Quicksort
        async function quicksort(data, low, high, stepCounter) {
            if (low < high) {
                let pivotIndex = await partition(data, low, high, stepCounter);
                await quicksort(data, low, pivotIndex - 1, stepCounter);
                await quicksort(data, pivotIndex + 1, high, stepCounter);
            }
        }

        async function partition(data, low, high, stepCounter) {
            let pivot = data[high];
            let i = low - 1;
            for (let j = low; j < high; j++) {
                if (data[j] < pivot) {
                    i++;
                    [data[i], data[j]] = [data[j], data[i]];
                    stepCounter.textContent = `Quicksort Steps: ${low}-${high}-${i}-${j}`;
                    await new Promise(resolve => requestAnimationFrame(resolve));
                    drawData(data1, data, data3);
                }
            }
            [data[i + 1], data[high]] = [data[high], data[i + 1]];
            stepCounter.textContent = `Quicksort Steps: ${low}-${high}-${i + 1}-${high}`;
            await new Promise(resolve => requestAnimationFrame(resolve));
            drawData(data1, data, data3);
            return i + 1;
        }

        // Mergesort
        async function mergesort(data, low, high, stepCounter) {
            if (low < high) {
                let mid = Math.floor((low + high) / 2);
                await mergesort(data, low, mid, stepCounter);
                await mergesort(data, mid + 1, high, stepCounter);
                await merge(data, low, mid, high, stepCounter);
            }
        }

        async function merge(data, low, mid, high, stepCounter) {
            let left = data.slice(low, mid + 1);
            let right = data.slice(mid + 1, high + 1);
            let i = 0;
            let j = 0;
            let k = low;
            while (i < left.length && j < right.length) {
                if (left[i] <= right[j]) {
                    data[k] = left[i];
                    i++;
                } else {
                    data[k] = right[j];
                    j++;
                }
                k++;
                stepCounter.textContent = `Mergesort Steps: ${low}-${high}-${i}-${j}`;
                await new Promise(resolve => requestAnimationFrame(resolve));
                drawData(data1, data2, data);
            }
            while (i < left.length) {
                data[k] = left[i];
                i++;
                k++;
                stepCounter.textContent = `Mergesort Steps: ${low}-${high}-${i}-${j}`;
                await new Promise(resolve => requestAnimationFrame(resolve));
                drawData(data1, data2, data);
            }
            while (j < right.length) {
                data[k] = right[j];
                j++;
                k++;
                stepCounter.textContent = `Mergesort Steps: ${low}-${high}-${i}-${j}`;
                await new Promise(resolve => requestAnimationFrame(resolve));
                drawData(data1, data2, data);
            }
        }

        // Start the sorting process
        async function startSorting() {
            initData();
            let data1 = [...data];
            let data2 = [...data];
            let data3 = [...data];
            drawData(data1, data2, data3);

            let bubbleSortStepCounter = document.createElement('p');
            bubbleSortStepCounter.textContent = 'Bubble Sort Steps: 0';
            document.body.appendChild(bubbleSortStepCounter);

            let quicksortStepCounter = document.createElement('p');
            quicksortStepCounter.textContent = 'Quicksort Steps: 0-0-0-0';
            document.body.appendChild(quicksortStepCounter);

            let mergesortStepCounter = document.createElement('p');
            mergesortStepCounter.textContent = 'Mergesort Steps: 0-0-0-0';
            document.body.appendChild(mergesortStepCounter);

            await bubbleSort(data1, bubbleSortStepCounter);
            await quicksort(data2, 0, data2.length - 1, quicksortStepCounter);
            await mergesort(data3, 0, data3.length - 1, mergesortStepCounter);
        }

        // Add event listener to the start button
        document.getElementById('start-button').addEventListener('click', startSorting);
    </script>
</body>
</html>
```

This code creates a simple HTML page with a canvas element and a start button. When the start button is clicked, it initializes a random dataset and starts the sorting process for bubble sort, quicksort, and mergesort. The sorting process is animated, and the step counters for each algorithm are updated in real-time. The time complexities of each algorithm are also displayed on the page.

Here's a simple HTML file that demonstrates the sorting algorithms you're interested in. This example uses JavaScript and HTML5 Canvas to animate the sorting process.

```html
<!DOCTYPE html>
<html>
<head>
    <title>Sorting Algorithm Comparison</title>
    <style>
        body {
            font-family: Arial, sans-serif;
        }
        canvas {
            border: 1px solid black;
        }
    </style>
</head>
<body>
    <h1>Sorting Algorithm Comparison</h1>
    <canvas id="canvas" width="800" height="400"></canvas>
    <button id="sort-button">Sort</button>
    <p id="complexity-info"></p>
    <p id="step-counts"></p>

    <script>
        // Get the canvas and context
        const canvas = document.getElementById('canvas');
        const ctx = canvas.getContext('2d');

        // Set up the data
        let data = [];
        const arraySize = 20;
        for (let i = 0; i < arraySize; i++) {
            data.push(Math.floor(Math.random() * 100) + 1);
        }

        // Draw the initial data
        drawData(data);

        // Define the sorting algorithms
        function bubbleSort(data) {
            let steps = 0;
            for (let i = 0; i < data.length; i++) {
                for (let j = 0; j < data.length - i - 1; j++) {
                    steps++;
                    if (data[j] > data[j + 1]) {
                        [data[j], data[j + 1]] = [data[j + 1], data[j]];
                        drawData(data, [j, j + 1]);
                        document.getElementById('step-counts').innerText = `Bubble Sort Steps: ${steps}`;
                        awaitSleep(10);
                    }
                }
            }
            return steps;
        }

        function mergeSort(data, low, high) {
            let steps = 0;
            if (low < high) {
                const mid = Math.floor((low + high) / 2);
                steps += mergeSort(data, low, mid);
                steps += mergeSort(data, mid + 1, high);
                steps += merge(data, low, mid, high);
            }
            return steps;
        }

        function merge(data, low, mid, high) {
            let steps = 0;
            const left = data.slice(low, mid + 1);
            const right = data.slice(mid + 1, high + 1);
            let i = 0, j = 0, k = low;
            while (i < left.length && j < right.length) {
                steps++;
                if (left[i] <= right[j]) {
                    data[k] = left[i];
                    i++;
                } else {
                    data[k] = right[j];
                    j++;
                }
                k++;
                drawData(data, [k - 1]);
                document.getElementById('step-counts').innerText = `Merge Sort Steps: ${steps}`;
                awaitSleep(10);
            }
            while (i < left.length) {
                data[k] = left[i];
                i++;
                k++;
                drawData(data, [k - 1]);
                document.getElementById('step-counts').innerText = `Merge Sort Steps: ${steps}`;
                awaitSleep(10);
            }
            while (j < right.length) {
                data[k] = right[j];
                j++;
                k++;
                drawData(data, [k - 1]);
                document.getElementById('step-counts').innerText = `Merge Sort Steps: ${steps}`;
                awaitSleep(10);
            }
            return steps;
        }

        function quickSort(data, low, high) {
            let steps = 0;
            if (low < high) {
                const pivotIndex = partition(data, low, high);
                steps += quickSort(data, low, pivotIndex - 1);
                steps += quickSort(data, pivotIndex + 1, high);
            }
            return steps;
        }

        function partition(data, low, high) {
            let steps = 0;
            const pivot = data[high];
            let i = low - 1;
            for (let j = low; j < high; j++) {
                steps++;
                if (data[j] < pivot) {
                    i++;
                    [data[i], data[j]] = [data[j], data[i]];
                    drawData(data, [i, j]);
                    document.getElementById('step-counts').innerText = `Quick Sort Steps: ${steps}`;
                    awaitSleep(10);
                }
            }
