                    arr[k] = left[i];
                    i++;
                } else {
                    arr[k] = right[j];
                    j++;
                }
                k++;
                yield [arr, steps];
            }
            while (i < left.length) {
                arr[k] = left[i];
                i++;
                k++;
                yield [arr, steps];
            }
            while (j < right.length) {
                arr[k] = right[j];
                j++;
                k++;
                yield [arr, steps];
