    async function mergeSort(arr, low, high, chartId, stepsElement) {
        if (low < high) {
            let mid = Math.floor((low + high) / 2);
            await mergeSort(arr, low, mid, chartId, stepsElement);
            await mergeSort(arr, mid + 1, high, chartId, stepsElement);
            await merge(arr, low, mid, high, chartId, stepsElement);
        }
    }

    async function merge(arr, low, mid, high, chartId, stepsElement) {
        let left = arr.slice(low, mid + 1);
        let right = arr.slice(mid + 1, high + 1);
        let i = 0, j = 0, k = low;
        while (i < left.length && j < right.length) {
            if (left[i] <= right[j]) {
                arr[k] = left[i];
                i++;
            } else {
                arr[k] = right[j];
                j++;
            }
            k++;
            drawBars(arr, chartId);
            stepsElement.textContent = `Steps: ${k}`;
            await new Promise(resolve => setTimeout(resolve, 10));
        }
        while (i < left.length) {
            arr[k] = left[i];
            i++;
            k++;
            drawBars(arr, chartId);
            stepsElement.textContent = `Steps: ${k}`;
            await new Promise(resolve => setTimeout(resolve, 10));
        }
        while (j < right.length) {
            arr[k] = right[j];
            j++;
            k++;
            drawBars(arr, chartId);
            stepsElement.textContent = `Steps: ${k}`;
            await new Promise(resolve => setTimeout(resolve, 10));
        }
    }

    function drawBars(arr, chartId) {
        let chart = document.getElementById(chartId);
        chart.innerHTML = '';
        let max = Math.max(...arr);
        let scale = chart.offsetHeight / max;
        arr.forEach((val, index) => {
            let bar = document.createElement('div');
            bar.className = 'bar';
            bar.style.left = `${index * (chart.offsetWidth / arr.length)}px`;
            bar.style.width = `${chart.offsetWidth / arr.length}px`;
            bar.style.height = `${val * scale}px`;
            chart.appendChild(bar);
        });
    }

    let bubbleArr = [5, 2, 8, 1, 9, 3, 7, 6, 4, 0, 12, 11, 10, 14, 13, 16, 15, 18, 17, 19];
    let quickArr = [...bubbleArr];
    let mergeArr = [...bubbleArr];

    let bubbleSteps = document.createElement('div');
    bubbleSteps.textContent = 'Steps: 0';
    document.body.appendChild(bubbleSteps);

    let quickSteps = document.createElement('div');
    quickSteps.textContent = 'Steps: 0';
    document.body.appendChild(quickSteps);

    let mergeSteps = document.createElement('div');
    mergeSteps.textContent = 'Steps: 0';
    document.body.appendChild(mergeSteps);

    drawBars(bubbleArr, 'bubble-chart');
    drawBars(quickArr, 'quick-chart');
    drawBars(mergeArr, 'merge-chart');

    bubbleSteps.style.position = 'absolute';
    bubbleSteps.style.top = '220px';
    bubbleSteps.style.left = '50px';

    quickSteps.style.position = 'absolute';
    quickSteps.style.top = '220px';
    quickSteps.style.left = '470px';

    mergeSteps.style.position = 'absolute';
    mergeSteps.style.top = '220px';
    mergeSteps.style.left = '890px';

    document.body.style.position = 'relative';
    document.body.style.width = '1500px';

    bubbleSort(bubbleArr, 'bubble-chart', bubbleSteps);
    quickSort(quickArr, 0, quickArr.length - 1, 'quick-chart', quickSteps);
    mergeSort(mergeArr, 0, mergeArr.length - 1, 'merge-chart', mergeSteps);
</script>

</body>
</html>
```

**Time Complexity Comparison:**

- **Bubble Sort:** O(n^2)
- **Quick Sort:** O(n log n) on average, O(n^2) in the worst case
- **Merge Sort:** O(n log n)

**Note:** This code snippet creates a simple visualization. The performance difference between these algorithms becomes more apparent with larger datasets. Also, keep in mind that the `setTimeout` function is used to slow down the animation for better visibility, which does not reflect real-world performance. 

Open this file in a browser to see the visualization. Adjustments might be needed for different screen sizes or for a more accurate representation. 

Bubble sort will be clearly outperformed by Quick Sort and Merge Sort, demonstrating visually why it's generally not used for large data sets.
